(function() {
  var hpiAdditionalNoteController = function($scope, $http, $rootScope,$ocLazyLoad,$modal, $timeout,$modalInstance,hpiAdditionalNoteService,initData) {
    $scope.selectedTab = 1;
    $scope.additionalNotes = undefined;
    $scope.guidanceImage = {
      headerImage:'data:image/jpg;base64,',
      footerImage:'data:image/jpg;base64,',
      symptomsImage:'data:image/jpg;base64,',
      showHeaderImage:false,
      showFooterImage:false,
      showSymptomsImage:false
    }
    var isHpiAddNotesConcurEnabled = false;
    var isHpiAddNotesCatConcurEnabled = false;

    $scope.initHpiAdditionalNote = function() {
      $scope.patientId = initData.patientId;
      $scope.encounterId = initData.encounterId;
      isHpiAddNotesConcurEnabled = getItemKeyValue("EnableConcurLock");
      if(isHpiAddNotesConcurEnabled.toLowerCase() === "yes"){
        isHpiAddNotesConcurEnabled = true;
        isHpiAddNotesCatConcurEnabled = getItemKeyValue("EnableCategoryConcurrency");
        if(isHpiAddNotesCatConcurEnabled.toLowerCase() === "yes") {
          isHpiAddNotesCatConcurEnabled = true;
        } else{
          isHpiAddNotesCatConcurEnabled = false;
        }
      } else{
        isHpiAddNotesConcurEnabled = false;
      }
      $scope.loadHpiAdditionalData(true);
      $('#hpiAdditionalModal').modal();
      if (initData.client && initData.client === 'EXE'){
        $("#headerNotesTabs").css({"height":"230px"});
        $("#footerNotesTabs").css({"height":"230px"});
        $("#symptomsTabs").css({"height":"230px"});
        $("#hpiAdditional1").css({"height":"350px",left:"20px"});
        $("#hpiAdditional2").css({"height":"350px",left:"-100px"});
        $("#hpiAdditional3").css({"height":"350px",left:"-200px"});
        setTimeout(function(){
          $(".additionalNoteModal .modal-dialog").draggable({ disabled: true });
        });
      }
    };

    $scope.selectTab = function(dataSize,tabNumber){
      if(dataSize>0){
        $scope.selectedTab = tabNumber;
      }
    }

    $scope.loadHpiAdditionalData = function(resetTabs){
      var aPromise = hpiAdditionalNoteService.getCategoryDetails($scope.encounterId, 0);
      aPromise.then(function(object) {
        $scope.additionalNotes = {headers:[], footers:[], symptoms:[], oHeaders:[], oFooters:[]}
        var x2js = new X2JS();
        var json = x2js.xml_str2json(object);
        var addNotes = json.Envelope.Body.return.additionalnotes;
        if (addNotes) {
          if (addNotes.headers) {
            $scope.additionalNotes.headers = $scope.returnArray(addNotes.headers.notes);
            $scope.additionalNotes.oHeaders = $scope.returnArray(addNotes.headers.notes);
          }

          if (addNotes.footers) {
            $scope.additionalNotes.footers = $scope.returnArray(addNotes.footers.notes);
            $scope.additionalNotes.oFooters = $scope.returnArray(addNotes.footers.notes);
          }

          if (addNotes.symptoms) {
            $scope.additionalNotes.symptoms = $scope.returnArray(addNotes.symptoms.symptom);
            for (var index in $scope.additionalNotes.symptoms) {
              $scope.additionalNotes.symptoms[index].suggestedcategories = $scope.returnArray($scope.additionalNotes.symptoms[index].suggestedcategories.suggestedcategory);
              $scope.additionalNotes.symptoms[index].enableCopyBtn = false;
              $scope.additionalNotes.symptoms[index].enableMergeBtn = false;
              if ($scope.additionalNotes.symptoms[index].suggestedcategories.length > 0) {
                $scope.additionalNotes.symptoms[index].suggestedCategoryId = $scope.additionalNotes.symptoms[index].suggestedcategories[0].suggestedCategoryId;
                $scope.additionalNotes.symptoms[index].enableCopyBtn = true;
                $scope.additionalNotes.symptoms[index].enableMergeBtn = true;
                if($scope.additionalNotes.symptoms[index].struct === '1' ){
                  if($scope.additionalNotes.symptoms[index].eligibleforcopy !== '1'){
                    $scope.additionalNotes.symptoms[index].enableCopyBtn = false;
                  }
                  $scope.additionalNotes.symptoms[index].enableMergeBtn = false;
                }
              }
            }
          }
        }
        if(resetTabs) {
          if ($scope.additionalNotes.headers.length > 0) {
            $scope.selectedTab = 1;
          } else if ($scope.additionalNotes.footers.length > 0) {
            $scope.selectedTab = 2;
          } else if ($scope.additionalNotes.symptoms.length > 0) {
            $scope.selectedTab = 3;
          }
        }
      });
    }



    $scope.saveSymptom = function (symptom, isCopy) {
      var msg = ""
      if (isCopy) {
        msg = "This action will overwrite any existing information currently"
            + " documented in the suggested Symptom Notes. Are you sure you"
            + " want to copy this Note?";
      } else {
        msg = "This action will merge with existing information currently "+
            "documented in the suggested Symptom Notes. Are you sure you "+
            "want to merge this Note?";
      }
      ecwConfirm(msg, "", function () {
        if(isHpiAddNotesConcurEnabled){
          hpiAdditionalNoteService.checkConcurrency($scope.encounterId,isHpiAddNotesCatConcurEnabled?symptom.suggestedCategoryId:0).then(function (object) {
            if(object && object.status === 'success'){
              saveSymptomCallback(symptom, isCopy);
            }else if(object && object.status === 'failed'){
              ecwAlert(object.message);
            }
          }, function errorCallback(error) {
            ecwAlert("Some Error occurred while checking concurrency.Please try again later");
          });
        } else{
          saveSymptomCallback(symptom, isCopy);
        }
      });
    }

    function saveSymptomCallback(symptom, isCopy) {
      var xml = createSetAdditionalSymptomXML(symptom);
      hpiAdditionalNoteService.saveSymptom($scope.encounterId, symptom.suggestedCategoryId, xml, isCopy).then(function (object) {
        if(symptom.struct === '1'){
          saveStructNotes(symptom);
        }
        $scope.deleteSymptomWithoutConfirm(symptom);
      }, function errorCallback(error) {
        ecwAlert("Some Error occurred while coping/merging unmapped data.Please try again later");
      });
    }

    $scope.deleteSymptom = function (symptom) {
      ecwConfirm("Are you sure you want to delete the note?", "", function () {
        $scope.deleteSymptomWithoutConfirm(symptom);
      });
    }
    $scope.deleteSymptomWithoutConfirm = function(symptom){
      hpiAdditionalNoteService.deleteSymptom($scope.encounterId, symptom.propId, symptom.notes).then(function (object) {
        $scope.loadHpiAdditionalData(false);
      }, function errorCallback(error) {
        ecwAlert("Some Error occurred while deleting unmapped data.Please try again later");
      });
    }

    function saveStructNotes(symptom){
      hpiAdditionalNoteService.saveStructNotes($scope.encounterId, symptom.suggestedCategoryId, symptom.propId).then(function (object) {
      }, function errorCallback(error) {
        ecwAlert("Some Error occurred while deleting unmapped data.Please try again later");
      });
    }

    var getONotes = function(noteType, index){
      var note = '';
      if(noteType === 'G'){
        note = $scope.additionalNotes.oHeaders[index];
      } else if(noteType === 'H'){
        note = $scope.additionalNotes.oFooters[index];
      }
      return note;
    }

    $scope.deleteNote = function (noteType, index) {
      ecwConfirm("Are you sure you want to delete the note?", "", function () {
        $scope.deleteNoteWithoutConfirm(getONotes(noteType, index), noteType);
      });
    }

    $scope.deleteNoteWithoutConfirm = function(note, noteType){
      hpiAdditionalNoteService.deleteNote($scope.encounterId, noteType, btoa(note)).then(function (object) {
        $scope.loadHpiAdditionalData(false);
      }, function errorCallback(error) {
        ecwAlert("Some Error occurred while deleting unmapped data.Please try again later");
      });
    }

    $scope.returnArray = function (data) {
      var response = [];
      if (Array.isArray(data)) {
        response = data;
      } else {
        response.push(data);
      }
      return response;
    }

    $scope.close = function () {
      $modalInstance.close('success');
      if (initData.client && initData.client === 'EXE'){
        closeVbFrmWeb();
        $scope.$destroy();
      }
    }

    $scope.openCategoryTree = function (notes, type, index) {

      var initModalData = {
        section: "HPI",
        client: initData.client
      };

      var modalUrl = "/mobiledoc/jsp/webemr/templates/category-tree-tpl.html";
      $ocLazyLoad.load({
        name: "categoryTreeApp",
        files: [
          '/mobiledoc/jsp/webemr/templates/category-tree-tpl.js',
          '/mobiledoc/jsp/webemr/progressnotes/templates/category-search.component.js'
        ],
        cache: true
      }).then(function () {
        var modalInstance = $modal.open({
          templateUrl: makeURL(modalUrl),
          controller: 'categoryTreeController',
          windowClass: 'app-modal-window bluetheme categoryTreeModal',
          backdrop: "static",
          resolve: {
            initModalData: function () {
              return initModalData;
            }
          }
        });

        modalInstance.result.then(function (selectedCategory) {
          if(selectedCategory){
            $scope.copyMergeNote(selectedCategory, notes, type, index)
          }
        }, function (response) {
        });

      }, function (e) {
        console.log(e);
      });
    };

    $scope.copyMergeNote = function (selectedCategory, notes, type, index) {
      var unmappedNoteMsg = "";
      if (selectedCategory.action === 'merge') {
        unmappedNoteMsg = "This action will merge with existing Notes. Are you sure you want to merge?";
      }else{
        unmappedNoteMsg = "This action will overwrite existing Notes. Are you sure you want to copy?";
      }
      ecwConfirm(unmappedNoteMsg, "", function() {
        if (selectedCategory.action === 'merge') {
          $scope.saveNotes(selectedCategory.id, notes, type,true, index);
        } else {
          $scope.saveNotes(selectedCategory.id, notes, type,false, index);
        }
      });
    }

    $scope.saveNotes = function (selectedCategoryId, notes, type,isMerge, index) {
      var notesJson = {notes:notes};
      if(isHpiAddNotesConcurEnabled){
        hpiAdditionalNoteService.checkConcurrency($scope.encounterId,isHpiAddNotesCatConcurEnabled?selectedCategoryId:0).then(function (object) {
          if(object && object.status === 'success'){
            saveNotesCallback(isMerge, selectedCategoryId, type, notesJson, index);
          }else if(object && object.status === 'failed'){
            ecwAlert(object.message);
          }
        }, function errorCallback(error) {
          ecwAlert("Some Error occurred while checking concurrency.Please try again later");
        });
      } else{
        saveNotesCallback(isMerge, selectedCategoryId, type, notesJson, index);
      }
    }

    function saveNotesCallback(isMerge, selectedCategoryId, type, notesJson, index) {
      hpiAdditionalNoteService.saveNotes(isMerge, $scope.encounterId, selectedCategoryId, type, notesJson).then(function (object) {
        $scope.deleteNoteWithoutConfirm(getONotes(type, index), type);
      }, function errorCallback(error) {
        ecwAlert("Some Error occurred while coping/merging unmapped data.Please try again later");
      });
    }

    $scope.showSymptomNotes = function(notes){
      $scope.currentSymptomNotes = notes;
      if($scope.currentSymptomNotes) {
        $("#additionalSymptomNotesModal").modal({backdrop: "static", keyboard: false});
      }
    };


    var createSetAdditionalSymptomXML = function (symptom) {
      var xw = new XMLWriter();
      startSoapPacket(xw);

      var notes = "";
      var htmlNotes = "";
      var selection = -1;

      if (symptom.section === 'Yes') {
        selection = 1;
      } else if (symptom.section === 'No') {
        selection = 0;
      }

      notes = symptom.notes;
      notes = replaceUTFCharWithASCII(notes);
      htmlNotes = "<![CDATA[" + replaceUTFCharWithASCII(symptom.notes2) + "]]>";
      try {
        htmlNotes = htmlNotes.replace(new RegExp("<br>", 'g'), "<BR>");
      } catch (err) {

      }

      xw.writeStartElement('item');
      xw.writeAttributeString('xsi:type', 'xsd:string');
      addElement(xw, 'propId', symptom.propId, 'xsi:type', 'xsd:string');
      addElement(xw, 'selection', selection, 'xsi:type', 'xsd:string');
      addElement(xw, 'duration', escapeXml(symptom.duration), 'xsi:type', 'xsd:string');
      addElement(xw, 'notes', "<![CDATA[" + notes + "]]>", 'xsi:type', 'xsd:string');
      addElement(xw, 'notes2', htmlNotes, 'xsi:type', 'xsd:string');
      xw.writeEndElement();

      xw.writeStartElement('hpiNotes');
      xw.writeAttributeString('xsi:type', 'xsd:string');
      addElement(xw, 'header', "", 'xsi:type', 'xsd:string');
      addElement(xw, 'footer', "", 'xsi:type', 'xsd:string');
      xw.writeEndElement();

      endSoapPacket(xw);
      return xw.flush();
    }
  }
  var hpiAdditionalNoteService = function($http){
    return {
      checkConcurrency: function (encounterId,categoryId) {
        var serverUrl = '/mobiledoc/emr/concurrency/check/Form3/'+encounterId+"/"+categoryId;
        serverUrl = makeURL(serverUrl);
        var aPromise = $http.get(serverUrl).then(function (response) {
          return response.data;
        }, function (response) {
          throw "Internal Error occured, Please try after some time";
        });
        return aPromise;
      },
      getCategoryDetails: function (encounterId, hpiId) {
        var serverUrl = '/mobiledoc/jsp/catalog/xml/getHpi.jsp?EncounterId=' + encounterId + '&HpiId=' + hpiId;
        serverUrl = makeURL(serverUrl);
        var aPromise = $http.get(serverUrl).then(function (response) {
          return response.data;
        }, function (response) {
          throw "Internal Error occured, Please try after some time";
        });
        return aPromise;
      },
      saveNotes: function (isMerge, encounterId, hpiId, type, requestBody) {
        var serverUrl = '/mobiledoc/clinicaldocumentation/hpi/unmapped/notes/'+isMerge+'/'+encounterId+'/'+hpiId+'/'+type;
        serverUrl = makeURL(serverUrl);
        var aPromise = $http({
          headers: {'Content-Type': 'application/json'},
          dataType: 'text',
          method: 'POST',
          url: serverUrl,
          data: requestBody
        }).then(function(response) {
          return  response.data;
        }, function(response) {
          throw "Internal Error occured, Please try after some time";
        });
        return aPromise;
      },
      saveSymptom: function (encounterId,hpiId,xmlData,isCopy) {
        var serverUrl = '/mobiledoc/clinicaldocumentation/hpi/unmapped/items/false';
        if(isCopy === 0){
          serverUrl = '/mobiledoc/clinicaldocumentation/hpi/unmapped/items/true';
        }
        serverUrl = makeURL(serverUrl + '?EncounterId=' + encounterId + '&HpiId=' + hpiId);
        var xsrf = $.param({FormData: xmlData});
        var aPromise = $http({
          headers: {'Content-Type': 'application/x-www-form-urlencoded'},
          dataType: 'text',
          method: 'POST',
          url: serverUrl,
          data: xsrf
        }).then(function(response) {
          return  response.data;
        }, function(response) {
          throw "Internal Error occured, Please try after some time";
        });
        return aPromise;
      },
      saveStructNotes: function (encounterId,catId,itemId) {
        var serverUrl = '/mobiledoc/emr/structdata/question/unmapped/items/struct/1/'+encounterId+'/'+catId+'/'+itemId;
        serverUrl = makeURL(serverUrl);
        var aPromise = $http({
          headers: {'Content-Type': 'application/x-www-form-urlencoded'},
          dataType: 'text',
          method: 'POST',
          url: serverUrl
        }).then(function(response) {
          return  response.data;
        }, function(response) {
          throw "Internal Error occured, Please try after some time";
        });
        return aPromise;
      },
      deleteNote: function (encounterId,type,notes) {
        var serverUrl = '/mobiledoc/clinicaldocumentation/hpi/unmapped/notes/'+encounterId+'/'+type;
        serverUrl = makeURL(serverUrl);
        var requestBody = {"notes":notes};
        var aPromise = $http({
          headers: {'Content-Type': 'application/json'},
          dataType: 'text',
          method: 'POST',
          url: serverUrl,
          data: requestBody
        }).then(function(response) {
          return  response.data;
        }, function(response) {
          throw "Internal Error occured, Please try after some time";
        });
        return aPromise;
      },
      deleteSymptom: function (encounterId,propId,notes) {
        var serverUrl = '/mobiledoc/clinicaldocumentation/hpi/unmapped/symptom/'+encounterId+'/'+propId;
        serverUrl = makeURL(serverUrl);
        var requestBody = {"notes":notes};
        var aPromise = $http({
          headers: {'Content-Type': 'application/json'},
          dataType: 'text',
          method: 'POST',
          url: serverUrl,
          data: requestBody
        }).then(function(response) {
          return  response.data;
        }, function(response) {
          throw "Internal Error occured, Please try after some time";
        });
        return aPromise;
      }
    }
  }
  var hpiAdditionalNoteApp = angular.module("hpiAdditionalNoteApp", ['ui.bootstrap','oc.lazyLoad']);
  hpiAdditionalNoteApp.controller("hpiAdditionalNoteController", hpiAdditionalNoteController);
  hpiAdditionalNoteApp.service('hpiAdditionalNoteService', hpiAdditionalNoteService);
})();